<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Spreadsheet</title>
<style>
  body {font-family:Arial,sans-serif;margin:20px;}
  table {border-collapse:collapse; min-width:600px; min-height:400px;}
  th, td {border:1px solid #aaa; padding:0;}
  th {background:#f0f0f0; text-align:center; width:60px; height:30px;}
  td {width:80px; height:30px;}
  input {width:100%; height:100%; box-sizing:border-box; border:none; padding:2px; font-size:14px;}
  input:focus {outline:2px solid #6cf;}
  #controls {margin-top:10px;}
  #export {margin-right:10px;}
  textarea {width:100%; height:150px; margin-top:5px; font-family:monospace;}
</style>
</head>
<body>
<table id="sheet">
  <thead>
    <tr><th></th>
      <th>A</th><th>B</th><th>C</th><th>D</th><th>E</th><th>F</th><th>G</th><th>H</th><th>I</th><th>J</th>
    </tr>
  </thead>
  <tbody>
    <!-- rows generated by script -->
  </tbody>
</table>

<div id="controls">
  <button id="export">Export CSV</button>
  <textarea id="csv" readonly></textarea>
</div>

<script>
(() => {
  const cols = ['A','B','C','D','E','F','G','H','I','J'];
  const rows = 10;
  const tbody = document.querySelector('#sheet tbody');

  // Build grid
  for(let r=1;r<=rows;r++){
    const tr=document.createElement('tr');
    const th=document.createElement('th');
    th.textContent=r;
    tr.appendChild(th);
    for(let c=0;c<cols.length;c++){
      const td=document.createElement('td');
      const input=document.createElement('input');
      const id=`cell-${cols[c]}${r}`;
      input.id=id;
      input.dataset.raw='';          // raw text
      input.dataset.display='';      // displayed (computed) value
      // focus -> show raw
      input.addEventListener('focus',function(){
        this.value=this.dataset.raw;
      });
      // blur or Enter -> commit raw and recompute
      const commit=()=>{ this.dataset.raw=this.value; recomputeAll(); };
      input.addEventListener('blur',commit);
      input.addEventListener('keydown',e=>{
        if(e.key==='Enter'){
          e.preventDefault();
          this.blur();
        }
      });
      td.appendChild(input);
      tr.appendChild(td);
    }
    tbody.appendChild(tr);
  }

  // Evaluation utilities
  const cellIdFromElement = el=>el.id.slice(5); // remove 'cell-'

  function evaluateCell(cellId, stack){
    const cell=document.getElementById('cell-'+cellId);
    const raw=cell.dataset.raw ?? '';
    // Plain value
    if(!raw.startsWith('=')){
      const trimmed=raw;
      if(trimmed===''){
        return {value:0, display:''};
      }
      const num=parseFloat(trimmed);
      if(!isNaN(num) && /^[+-]?\d+(\.\d+)?$/.test(trimmed)){
        return {value:num, display:trimmed};
      }
      // non‑numeric text
      return {value:0, display:trimmed};
    }
    // Formula
    if(stack.has(cellId)){
      return {value:NaN, display:'#CYCLE', cycle:true};
    }
    const expr=raw.slice(1);
    stack.add(cellId);
    const res=evalFormula(expr, stack);
    stack.delete(cellId);
    if(res.cycle){
      return {value:NaN, display:'#CYCLE', cycle:true};
    }
    if(res.error){
      return {value:NaN, display:'#ERR', error:true};
    }
    return {value:res.value, display:String(res.value)};
  }

  function evalFormula(expr, stack){
    const refRegex=/\b([A-J](?:[1-9]|10))\b/g;
    let replaced;
    try{
      replaced=expr.replace(refRegex,(match,ref)=>{
        const r=evaluateCell(ref,stack);
        if(r.cycle) throw {type:'cycle'};
        if(r.error) throw {type:'error'};
        return r.value;
      });
    }catch(e){
      if(e.type==='cycle') return {cycle:true};
      return {error:true};
    }
    // Disallow any characters other than numbers, operators, parentheses, dot, whitespace
    if(/[^0-9+\-*/().\s]/.test(replaced)){
      return {error:true};
    }
    try{
      const val=Function('"use strict";return ('+replaced+')')();
      if(typeof val==='number' && isFinite(val)){
        return {value:val};
      }
      return {error:true};
    }catch{
      return {error:true};
    }
  }

  function recomputeAll(){
    for(let r=1;r<=rows;r++){
      for(let c=0;c<cols.length;c++){
        const id=`${cols[c]}${r}`;
        const cell=document.getElementById('cell-'+id);
        const res=evaluateCell(id,new Set());
        cell.dataset.display=res.display;
        if(document.activeElement!==cell){
          cell.value=res.display;
        }
      }
    }
  }

  // Export CSV
  document.getElementById('export').addEventListener('click',()=>{
    const lines=[];
    for(let r=1;r<=rows;r++){
      const line=[];
      for(let c=0;c<cols.length;c++){
        const id=`${cols[c]}${r}`;
        const cell=document.getElementById('cell-'+id);
        line.push(cell.dataset.display);
      }
      lines.push(line.join(','));
    }
    document.getElementById('csv').value=lines.join('\n');
  });

  // Expose API
  window.sheet={
    set(cellId,text){
      const cell=document.getElementById('cell-'+cellId);
      if(!cell) return;
      cell.dataset.raw=text;
      recomputeAll();
    },
    get(cellId){
      const cell=document.getElementById('cell-'+cellId);
      return cell?cell.dataset.display:'';
    },
    raw(cellId){
      const cell=document.getElementById('cell-'+cellId);
      return cell?cell.dataset.raw:'';
    }
  };

  // Initial recompute (all empty)
  recomputeAll();
})();
</script>
</body>
</html>
